'use strict';

var $SyntaxError = require('es-errors/syntax');
var $TypeError = require('es-errors/type');

var IsDetachedBuffer = require('./IsDetachedBuffer');
var IsInteger = require('./IsInteger');
var SetValueInBuffer = require('./SetValueInBuffer');
var ToNumber = require('./ToNumber');

var isNegativeZero = require('math-intrinsics/isNegativeZero');
var typedArrayBuffer = require('typed-array-buffer');
var typedArrayByteOffset = require('typed-array-byte-offset');
var typedArrayLength = require('typed-array-length');
var whichTypedArray = require('which-typed-array');

var tableTAO = require('./tables/typed-array-objects');



module.exports = function IntegerIndexedElementSet(O, index, value) {
	if (typeof index !== 'number') {
		throw new $TypeError('`index` must be a Number'); 
	}
	var arrayTypeName = whichTypedArray(O); 
	if (!arrayTypeName) {
		throw new $TypeError('`O` must be a TypedArray'); 
	}
	if (arrayTypeName === 'BigInt64Array' || arrayTypeName === 'BigUint64Array') {
		throw new $SyntaxError('BigInt64Array and BigUint64Array do not exist until ES2020'); 
	}

	var numValue = ToNumber(value); 

	var buffer = typedArrayBuffer(O); 

	if (IsDetachedBuffer(buffer)) {
		throw new $TypeError('`O` has a detached buffer'); 
	}

	if (!IsInteger(index) || isNegativeZero(index)) {
		return false; 
	}

	var length = typedArrayLength(O); 

	if (index < 0 || index >= length) {
		return false; 
	}

	var offset = typedArrayByteOffset(O); 

	var elementType = tableTAO.name['$' + arrayTypeName]; 

	var elementSize = tableTAO.size['$' + elementType]; 

	var indexedPosition = (index * elementSize) + offset; 

	SetValueInBuffer(buffer, indexedPosition, elementType, numValue); 

	return true; 
};
